// This code was generated by ChatGPT

import {
  HandLandmarker,
  FilesetResolver,
  DrawingUtils
} from "https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@0.10.3/vision_bundle.mjs";

/* -------------------- Role + WS helpers -------------------- */
function getRole() {
  return window.__APP_ROLE__ || null;
}
function getWS() {
  return window.__APP_WS__ || null;
}
function wsSend(obj) {
  const ws = getWS();
  if (!ws || ws.readyState !== 1) return;
  ws.send(JSON.stringify(obj));
}

/* -------------------- DOM -------------------- */
const webcamButton = document.getElementById("webcamButton");
const video = document.getElementById("webcam");
const mpCanvas = document.getElementById("output_canvas");
const mpCtx = mpCanvas ? mpCanvas.getContext("2d") : null;
const expertDebug = document.getElementById("expert_debug");

const mvExpert = document.getElementById("mv_expert");
const mvNovice = document.getElementById("mv_novice");

const glowCanvasExpert = document.getElementById("glow_canvas_expert");
const glowCanvasNovice = document.getElementById("glow_canvas_novice");
const noviceReadout = document.getElementById("novice_readout");

/* -------------------- Shared settings -------------------- */
const MIRRORED_VIEW = true;

// Increased from 0.07 → 0.12 to make bottom edge easier to hit
const EDGE_ZONE = 0.12;

// Hand landmark indices
const THUMB_TIP = 4;
const THUMB_MCP = 2;

const INDEX_TIP = 8;
const INDEX_PIP = 6;

const MIDDLE_TIP = 12;
const MIDDLE_PIP = 10;

const RING_TIP = 16;
const RING_PIP = 14;

const PINKY_TIP = 20;
const PINKY_PIP = 18;

/* -------------------- Object state -------------------- */
/*
  ALIGN uses visible screen-space mm.
  ROTATE uses model-viewer orientation.
*/
let posXmm = 0;
let posYmm = 0;

let rotX = 0;
let rotY = 0;
let rotZ = 0;

// novice receives this from WS
let remoteState = {
  posXmm: 0,
  posYmm: 0,
  rotX: 0,
  rotY: 0,
  rotZ: 0,
  glowEdge: null,
  tool: "none",
  stepLabel: "none"
};

let lastSendMs = 0;
const SEND_INTERVAL_MS = 33;

// tap detection
let previousEdge = null;
const TAP_COOLDOWN_MS = 160;
let lastTapMs = 0;

/* -------------------- Geometry helpers -------------------- */
function edgeFromPoint(pt) {
  let x = pt.x;
  const y = pt.y;

  if (MIRRORED_VIEW) x = 1 - x;

  const edgeX = EDGE_ZONE;
  const edgeTop = EDGE_ZONE;
  const edgeBottom = EDGE_ZONE + 0.04; // extra forgiveness for bottom

  const nearLeft = x < edgeX;
  const nearRight = x > 1 - edgeX;
  const nearTop = y < edgeTop;
  const nearBottom = y > 1 - edgeBottom;

  if (nearTop && nearLeft) return "TOP_LEFT";
  if (nearTop && nearRight) return "TOP_RIGHT";
  if (nearBottom && nearLeft) return "BOTTOM_LEFT";
  if (nearBottom && nearRight) return "BOTTOM_RIGHT";

  if (nearLeft) return "LEFT";
  if (nearRight) return "RIGHT";
  if (nearTop) return "TOP";
  if (nearBottom) return "BOTTOM";

  return null;
}

function drawEdgeGlow(ctx, w, h, edge) {
  if (!edge) return;

  if (edge === "TOP_LEFT") {
    drawEdgeGlow(ctx, w, h, "TOP");
    drawEdgeGlow(ctx, w, h, "LEFT");
    return;
  }
  if (edge === "TOP_RIGHT") {
    drawEdgeGlow(ctx, w, h, "TOP");
    drawEdgeGlow(ctx, w, h, "RIGHT");
    return;
  }
  if (edge === "BOTTOM_LEFT") {
    drawEdgeGlow(ctx, w, h, "BOTTOM");
    drawEdgeGlow(ctx, w, h, "LEFT");
    return;
  }
  if (edge === "BOTTOM_RIGHT") {
    drawEdgeGlow(ctx, w, h, "BOTTOM");
    drawEdgeGlow(ctx, w, h, "RIGHT");
    return;
  }

  const t = Math.max(2, Math.round(Math.min(w, h) * EDGE_ZONE));

  ctx.save();
  ctx.shadowColor = "rgba(120, 200, 255, 0.95)";
  ctx.shadowBlur = 28;
  ctx.fillStyle = "rgba(120, 200, 255, 0.35)";

  if (edge === "LEFT") ctx.fillRect(0, 0, t, h);
  if (edge === "RIGHT") ctx.fillRect(w - t, 0, t, h);
  if (edge === "TOP") ctx.fillRect(0, 0, w, t);
  if (edge === "BOTTOM") ctx.fillRect(0, h - t, w, t);

  ctx.restore();
}

function perceivedHandLabel(mpLabel) {
  if (!mpLabel) return null;
  if (!MIRRORED_VIEW) return mpLabel;
  return mpLabel === "Left" ? "Right" : mpLabel === "Right" ? "Left" : mpLabel;
}

/* -------------------- Finger helpers -------------------- */
function isFingerUp(landmarks, tipIdx, pipIdx) {
  return landmarks[tipIdx].y < landmarks[pipIdx].y;
}

function dist(a, b) {
  const dx = a.x - b.x;
  const dy = a.y - b.y;
  return Math.sqrt(dx * dx + dy * dy);
}

function isThumbOpen(landmarks) {
  const thumbTip = landmarks[THUMB_TIP];
  const thumbMcp = landmarks[THUMB_MCP];
  const indexPip = landmarks[INDEX_PIP];
  return dist(thumbTip, thumbMcp) > dist(thumbMcp, indexPip) * 0.7;
}

function isOneFingerUp(landmarks) {
  const indexUp = isFingerUp(landmarks, INDEX_TIP, INDEX_PIP);
  const middleDown = !isFingerUp(landmarks, MIDDLE_TIP, MIDDLE_PIP);
  const ringDown = !isFingerUp(landmarks, RING_TIP, RING_PIP);
  const pinkyDown = !isFingerUp(landmarks, PINKY_TIP, PINKY_PIP);
  return indexUp && middleDown && ringDown && pinkyDown;
}

function isTwoFingersUp(landmarks) {
  const indexUp = isFingerUp(landmarks, INDEX_TIP, INDEX_PIP);
  const middleUp = isFingerUp(landmarks, MIDDLE_TIP, MIDDLE_PIP);
  const ringDown = !isFingerUp(landmarks, RING_TIP, RING_PIP);
  const pinkyDown = !isFingerUp(landmarks, PINKY_TIP, PINKY_PIP);
  return indexUp && middleUp && ringDown && pinkyDown;
}

function getRightHandStep(landmarks) {
  const indexUp = isFingerUp(landmarks, INDEX_TIP, INDEX_PIP);
  const middleUp = isFingerUp(landmarks, MIDDLE_TIP, MIDDLE_PIP);
  const ringUp = isFingerUp(landmarks, RING_TIP, RING_PIP);
  const pinkyUp = isFingerUp(landmarks, PINKY_TIP, PINKY_PIP);
  const thumbUp = isThumbOpen(landmarks);

  // 5 fingers up => 10mm / 10deg
  if (indexUp && middleUp && ringUp && pinkyUp && thumbUp) {
    return {
      moveMm: 10,
      rotateDeg: 10,
      label: "10mm / 10°"
    };
  }

  // 3 fingers up => 5mm / 5deg
  if (indexUp && middleUp && ringUp && !pinkyUp) {
    return {
      moveMm: 5,
      rotateDeg: 5,
      label: "5mm / 5°"
    };
  }

  // 1 finger up => 1mm / 1deg
  if (indexUp && !middleUp && !ringUp && !pinkyUp) {
    return {
      moveMm: 1,
      rotateDeg: 1,
      label: "1mm / 1°"
    };
  }

  return null;
}

/* -------------------- Canvas sizing helpers -------------------- */
function fitCanvasToCSS(canvas, ctx) {
  const dpr = window.devicePixelRatio || 1;
  const rect = canvas.getBoundingClientRect();
  const w = Math.max(1, Math.round(rect.width));
  const h = Math.max(1, Math.round(rect.height));

  const needResize =
    canvas.width !== Math.round(w * dpr) ||
    canvas.height !== Math.round(h * dpr);

  if (needResize) {
    canvas.width = Math.round(w * dpr);
    canvas.height = Math.round(h * dpr);
  }

  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
  return { w, h };
}

/* -------------------- Apply to <model-viewer> -------------------- */
function applyPoseToModelViewer(el, xMm, yMm, xDeg, yDeg, zDeg) {
  if (!el) return;

  // visible screen-space translation
  el.style.transformOrigin = "50% 50%";
  el.style.transform = `translate(${xMm}mm, ${-yMm}mm)`;

  // actual 3D orientation
  el.orientation = `${xDeg}deg ${yDeg}deg ${zDeg}deg`;
}

/* ============================================================
   NOVICE: render-only
   ============================================================ */
let noviceRaf = null;

function startNovice() {
  function render() {
    if (glowCanvasNovice) {
      const ctx = glowCanvasNovice.getContext("2d");
      const { w, h } = fitCanvasToCSS(glowCanvasNovice, ctx);
      ctx.clearRect(0, 0, w, h);
      drawEdgeGlow(ctx, w, h, remoteState.glowEdge);
    }

    applyPoseToModelViewer(
      mvNovice,
      remoteState.posXmm,
      remoteState.posYmm,
      remoteState.rotX,
      remoteState.rotY,
      remoteState.rotZ
    );

    if (noviceReadout) {
      noviceReadout.textContent = [
        `Tool: ${remoteState.tool || "none"}`,
        `Step: ${remoteState.stepLabel || "none"}`,
        `Edge: ${remoteState.glowEdge || "none"}`,
        `Pos(mm): (${remoteState.posXmm.toFixed(1)}, ${remoteState.posYmm.toFixed(1)})`,
        `Rot(deg): x=${remoteState.rotX.toFixed(1)} y=${remoteState.rotY.toFixed(1)} z=${remoteState.rotZ.toFixed(1)}`
      ].join("\n");
    }

    noviceRaf = requestAnimationFrame(render);
  }

  render();
}

/* ============================================================
   EXPERT: MediaPipe + broadcast
   ============================================================ */
let handLandmarker = null;
let runningMode = "IMAGE";
let webcamRunning = false;
let lastVideoTime = -1;
let expertRaf = null;

async function createLandmarker() {
  const vision = await FilesetResolver.forVisionTasks(
    "https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@0.10.3/wasm"
  );

  handLandmarker = await HandLandmarker.createFromOptions(vision, {
    baseOptions: {
      modelAssetPath:
        "https://storage.googleapis.com/mediapipe-models/hand_landmarker/hand_landmarker/float16/1/hand_landmarker.task",
      delegate: "GPU"
    },
    runningMode,
    numHands: 2
  });

  if (expertDebug) expertDebug.textContent = "HandLandmarker ready.";
}

function stopWebcam() {
  if (!video) return;
  const stream = video.srcObject;
  if (stream && stream.getTracks) stream.getTracks().forEach((t) => t.stop());
  video.srcObject = null;
}

function applySingleTapStep(tool, edge, step) {
  if (!step || !edge) return;

  if (tool === "Align") {
    if (edge === "LEFT") posXmm -= step.moveMm;
    if (edge === "RIGHT") posXmm += step.moveMm;
    if (edge === "TOP") posYmm += step.moveMm;
    if (edge === "BOTTOM") posYmm -= step.moveMm;

    if (edge === "TOP_LEFT") {
      posXmm -= step.moveMm;
      posYmm += step.moveMm;
    }
    if (edge === "TOP_RIGHT") {
      posXmm += step.moveMm;
      posYmm += step.moveMm;
    }
    if (edge === "BOTTOM_LEFT") {
      posXmm -= step.moveMm;
      posYmm -= step.moveMm;
    }
    if (edge === "BOTTOM_RIGHT") {
      posXmm += step.moveMm;
      posYmm -= step.moveMm;
    }
  }

  if (tool === "Rotate") {
    if (edge === "TOP_LEFT" || edge === "BOTTOM_LEFT") {
      rotZ -= step.rotateDeg;
    } else if (edge === "TOP_RIGHT" || edge === "BOTTOM_RIGHT") {
      rotZ += step.rotateDeg;
    } else if (edge === "TOP") {
      rotX -= step.rotateDeg;
    } else if (edge === "BOTTOM") {
      rotX += step.rotateDeg;
    } else if (edge === "LEFT") {
      rotY -= step.rotateDeg;
    } else if (edge === "RIGHT") {
      rotY += step.rotateDeg;
    }
  }

  // keep it sane/visible
  posXmm = Math.max(-120, Math.min(120, posXmm));
  posYmm = Math.max(-120, Math.min(120, posYmm));

  rotX = Math.max(-85, Math.min(85, rotX));

  if (rotY > 180) rotY -= 360;
  if (rotY < -180) rotY += 360;
  if (rotZ > 180) rotZ -= 360;
  if (rotZ < -180) rotZ += 360;
}

function startExpert() {
  if (!webcamButton || !video || !mpCanvas || !expertDebug) return;

  webcamButton.addEventListener("click", async () => {
    if (!handLandmarker) {
      expertDebug.textContent = "Loading MediaPipe…";
      await createLandmarker();
    }

    webcamRunning = !webcamRunning;
    webcamButton.innerText = webcamRunning ? "DISABLE" : "ENABLE";

    if (!webcamRunning) {
      stopWebcam();
      if (expertRaf) cancelAnimationFrame(expertRaf);
      expertRaf = null;
      return;
    }

    const stream = await navigator.mediaDevices.getUserMedia({
      video: { width: { ideal: 1280 }, height: { ideal: 720 } }
    });
    video.srcObject = stream;

    video.addEventListener("loadeddata", predictWebcam, { once: true });
  });
}

async function predictWebcam() {
  if (!webcamRunning || !handLandmarker) return;

  if (runningMode === "IMAGE") {
    runningMode = "VIDEO";
    await handLandmarker.setOptions({ runningMode: "VIDEO" });
  }

  mpCanvas.width = video.videoWidth;
  mpCanvas.height = video.videoHeight;

  const nowInMs = performance.now();

  let results;
  if (video.currentTime !== lastVideoTime) {
    lastVideoTime = video.currentTime;
    results = handLandmarker.detectForVideo(video, nowInMs);
  } else {
    expertRaf = requestAnimationFrame(predictWebcam);
    return;
  }

  mpCtx.save();
  mpCtx.clearRect(0, 0, mpCanvas.width, mpCanvas.height);
  mpCtx.globalAlpha = 1;
  mpCtx.filter = "none";
  mpCtx.shadowBlur = 0;
  mpCtx.shadowColor = "transparent";

  const drawingUtils = new DrawingUtils(mpCtx);
  const landmarksArr = results.landmarks ?? [];
  const handednessArr = results.handednesses ?? [];

  let rightHand = null;
  let leftHand = null;

  for (let i = 0; i < landmarksArr.length; i++) {
    const landmarks = landmarksArr[i];

    drawingUtils.drawConnectors(landmarks, HandLandmarker.HAND_CONNECTIONS, { lineWidth: 4 });
    drawingUtils.drawLandmarks(landmarks, { lineWidth: 2 });

    const mpLabel = handednessArr[i]?.[0]?.displayName;
    const perceived = perceivedHandLabel(mpLabel);

    if (perceived === "Right") rightHand = landmarks;
    if (perceived === "Left") leftHand = landmarks;
  }

  // LEFT HAND chooses tool
  let tool = "none";
  const leftOne = leftHand ? isOneFingerUp(leftHand) : false;
  const leftTwo = leftHand ? isTwoFingersUp(leftHand) : false;

  if (leftTwo) tool = "Rotate";
  else if (leftOne) tool = "Align";

  // RIGHT HAND chooses step size
  const step = rightHand ? getRightHandStep(rightHand) : null;

  // RIGHT HAND edge with bottom fallback
  let glowEdge = null;
  let didTap = false;

  if ((tool === "Align" || tool === "Rotate") && rightHand && step) {
    const tipEdge = edgeFromPoint(rightHand[INDEX_TIP]);
    const pipEdge = edgeFromPoint(rightHand[INDEX_PIP]);

    glowEdge = tipEdge;

    // bottom fallback: fingertip often gets lost first near bottom
    if (!glowEdge && pipEdge === "BOTTOM") glowEdge = "BOTTOM";
    if (!glowEdge && pipEdge === "BOTTOM_LEFT") glowEdge = "BOTTOM_LEFT";
    if (!glowEdge && pipEdge === "BOTTOM_RIGHT") glowEdge = "BOTTOM_RIGHT";

    const now = performance.now();
    const enteringEdge = glowEdge && previousEdge === null;
    const cooldownPassed = now - lastTapMs > TAP_COOLDOWN_MS;

    if (enteringEdge && cooldownPassed) {
      applySingleTapStep(tool, glowEdge, step);
      didTap = true;
      lastTapMs = now;
    }
  }

  previousEdge = glowEdge || null;

  applyPoseToModelViewer(mvExpert, posXmm, posYmm, rotX, rotY, rotZ);

  if (glowCanvasExpert) {
    const ctx = glowCanvasExpert.getContext("2d");
    const { w, h } = fitCanvasToCSS(glowCanvasExpert, ctx);
    ctx.clearRect(0, 0, w, h);
    drawEdgeGlow(ctx, w, h, glowEdge);
  }

  mpCtx.restore();

  if (expertDebug) {
    expertDebug.textContent = [
      `Tool: ${tool}`,
      `Left hand: ${leftHand ? "detected" : "not detected"} ${
        leftHand ? (leftTwo ? "(2 fingers)" : leftOne ? "(1 finger)" : "(no tool)") : ""
      }`,
      `Right hand: ${rightHand ? "detected" : "not detected"} ${step ? `(${step.label})` : ""}`,
      `Edge: ${glowEdge ?? "none"}${didTap ? " [tap]" : ""}`,
      `Pos(mm): (${posXmm.toFixed(1)}, ${posYmm.toFixed(1)})`,
      `Rot(deg): x=${rotX.toFixed(1)} y=${rotY.toFixed(1)} z=${rotZ.toFixed(1)}`
    ].join("\n");
  }

  const t = performance.now();
  if (t - lastSendMs >= SEND_INTERVAL_MS) {
    lastSendMs = t;
    wsSend({
      type: "state",
      posXmm,
      posYmm,
      rotX,
      rotY,
      rotZ,
      glowEdge,
      tool,
      stepLabel: step ? step.label : "none"
    });
  }

  expertRaf = requestAnimationFrame(predictWebcam);
}

/* ============================================================
   Receive WS messages
   ============================================================ */
window.addEventListener("app:ws", (e) => {
  const msg = e.detail;
  if (!msg || typeof msg !== "object") return;

  if (msg.type === "joined") {
    if (msg.modelUrl) {
      if (mvNovice) mvNovice.src = msg.modelUrl;
      if (mvExpert) mvExpert.src = msg.modelUrl;
    }
    if (msg.state) {
      remoteState = {
        ...remoteState,
        ...msg.state
      };
    }
    return;
  }

  if (msg.type === "model") {
    if (mvNovice) mvNovice.src = msg.url;
    return;
  }

  if (msg.type === "state") {
    remoteState = {
      posXmm: msg.posXmm ?? remoteState.posXmm,
      posYmm: msg.posYmm ?? remoteState.posYmm,
      rotX: msg.rotX ?? remoteState.rotX,
      rotY: msg.rotY ?? remoteState.rotY,
      rotZ: msg.rotZ ?? remoteState.rotZ,
      glowEdge: msg.glowEdge ?? null,
      tool: msg.tool ?? "none",
      stepLabel: msg.stepLabel ?? "none"
    };
  }
});

/* ============================================================
   Boot
   ============================================================ */
window.addEventListener("app:joined", () => {
  const role = getRole();
  if (role === "expert") startExpert();
  else if (role === "novice") startNovice();
});

// dev fallback
(() => {
  const role = getRole();
  if (!role && (mvNovice || noviceReadout)) startNovice();
})();